TableLib={}function TableLib.nums(a)local b=TableLib.checktable(a)local c=0;for d,e in pairs(b)do c=c+1 end;return c end;function TableLib.merge(f,g)if not g or not f then return end;for d,e in pairs(g)do f[d]=e end end;function TableLib.merge_newtable(h,i)local j={}if h and next(h)then for d,e in pairs(h)do table.insert(j,e)end end;if i and next(i)then for d,e in pairs(i)do table.insert(j,e)end end;return j end;function TableLib.key_of(k,l)for d,e in pairs(k)do if e==l then return d end end;return nil end;function TableLib.index_of(m,l,n)for o=n or 1,#m do if m[o]==l then return o end end;return false end;function TableLib.remove_by_value(m,l,p)local q,o,r=0,1,#m;while o<=r do if m[o]==l then table.remove(m,o)q=q+1;o=o-1;r=r-1;if not p then break end end;o=o+1 end;return q end;function TableLib.is_empty(a)if a and type(a)=="table"then return next(a)==nil end;return true end;function TableLib.copy_tab(s)local t={}for d,e in pairs(s or{})do if type(e)~="table"then t[d]=e else t[d]=TableLib.copy_tab(e)end end;return t end;function TableLib.copy_to(u,v)for w,e in ipairs(v or{})do table.insert(u,e)end end;function TableLib.checktable(a)return verify(a)end;function verify(a)if a and type(a)=="table"then return a end;return{}end;function table_size(a)if type(a)~="table"then return 0 end;local c=0;for w,e in pairs(a)do c=c+1 end;return c end;function TableLib.equal(x,y)if type(x)~=type(y)then return false else if type(x)~="table"then return x==y else local z=table_size(x)local A=table_size(y)if z~=A then return false else local B=true;for d,e in pairs(x)do if y[d]==nil then B=false;break else if type(y[d])~=type(e)then B=false;break else if type(e)~="table"then if y[d]~=e then B=false;break end else B=TableLib.equal(e,y[d])if not B then break end end end end end;return B end end end end;function TableLib.deep_merge(g,...)local C={...}for o,D in ipairs(C)do for d,e in pairs(D)do if type(e)=="table"and type(g[d])=="table"then TableLib.deep_merge(g[d],e)else g[d]=e end end end end;function TableLib.select(a,E)local b={}for o,e in ipairs(a)do if E and E(o,e)==true then b[#b+1]=e end end;return b end;function TableLib.lock_write(a)local F=getmetatable(a)or{}F.__newindex=function(w,d,e)error(string.format("can't write [%s] into table.the table is locked,use release_lock_write to release",d))end;if not getmetatable(a)then setmetatable(a,F)end end;function TableLib.release_lock_write(a)local F=getmetatable(a)if not(F and F.__newindex)then return end;F.__newindex=nil end;function TableLib.get_subset(a,G,H)assert(G>0 and G<=H and H<=#a,string.format("invalid range : %d, %d",G,H))local I={}for o=G,H do I[#I+1]=a[o]end;return I end;function TableLib.load_str_tab(J)if string.match(J,"^%s*%{.*%}%s*$")then return loadstring("return "..J)()end;return J end;function TableLib.all_keys(t)if next(t)==nil then print("nilTab")return end;local K={}for d,w in pairs(t)do table.insert(K,d)end;return K end
